def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.25:
            score = (1 - ratio) ** 3 * 20
        elif 0.25 <= ratio < 0.75:
            score = np.log1p(ratio * 10) * 15
            if capacity % 2 == 0:
                score += 5
            else:
                score -= 3
        elif 0.75 <= ratio <= 1:
            score = 50 - (ratio * 40)
            for k in range(1, 5):
                score += ((-1) ** k) * (k * ratio)
        else:
            penalty = 0
            for j in range(1, 6):
                penalty += (ratio - 1) ** j * (j ** 2)
                if j % 2 == 0 and capacity < item * (j * 0.5):
                    penalty += 10 / j
            score = penalty * 7
            if capacity < item * 1.2:
                score += 20
        remainder = capacity - item
        if remainder < 0:
            score += abs(remainder) * 30
            if remainder < -item * 0.5:
                score += 50
        else:
            div_sum = 0
            for d in range(1, int(remainder)+1):
                if remainder % d == 0:
                    div_sum += d * 0.05
            score -= div_sum
        if i % 3 == 0:
            score *= 1.1
        if i % 5 == 0:
            score += 2
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_val = np.max(finite_priorities)
        priorities[np.isinf(priorities)] = max_val + 500
    else:
        priorities[np.isinf(priorities)] = 1000
    return priorities
